function createBaseInput(): CalcularCotizacionInput {
  return {
    organizationId: 77,
    proyectoId: 300,
    estado: "borrador",
    descuentoPct: 10,
    items: [
      {
        organizationId: 77,
        productTypeId: 1,
        systemLineId: 10,
        configurationId: 100,
        cantidad: 2,
        ancho: 2000,
        alto: 1500,
        color: "Negro",
      },
    ],
  };
}

describe("cotizador.service", () => {
  it("debe calcular un item configurable y totalizar la cotizacion", async () => {
    const service = createCotizadorService({
      catalogoRepository: createCatalogoRepositoryMock(),
      cotizacionesRepository: createCotizacionesRepositoryMock(),
    });

    const resultado = await service.calcularCotizacion(createBaseInput());

    expect(resultado.subtotalNeto).toBe(333000);
    expect(resultado.iva).toBe(63270);
    expect(resultado.total).toBe(396270);
    expect(resultado.costoTotal).toBe(296000);
    expect(resultado.items).toHaveLength(1);
    expect(resultado.items[0]).toMatchObject({
      linea: "S60",
      vidrio: "Vidrio incoloro 6mm",
      areaM2: 3,
      costoUnitario: 148000,
      precioUnitario: 185000,
      subtotal: 370000,
      tipoItem: "configurado",
    });
    expect(resultado.items[0].breakdown).toHaveLength(4);
  });

  it("debe fallar si el vidrio seleccionado no es compatible", async () => {
    const service = createCotizadorService({
      catalogoRepository: createCatalogoRepositoryMock(),
      cotizacionesRepository: createCotizacionesRepositoryMock(),
    });

    await expect(
      service.calcularCotizacion({
        ...createBaseInput(),
        items: [
          {
            ...createBaseInput().items[0],
            glassMaterialId: 9999,
          },
        ],
      })
    ).rejects.toThrow("El vidrio seleccionado no es compatible con la linea");
  });

  it("debe persistir la cotizacion calculada usando el repository", async () => {
    const catalogoRepository = createCatalogoRepositoryMock();
    const cotizacionesRepository = createCotizacionesRepositoryMock();
    const service = createCotizadorService({
      catalogoRepository,
      cotizacionesRepository,
    });

    const cotizacion = await service.crearCotizacion(createBaseInput());

    expect(cotizacionesRepository.create).toHaveBeenCalledTimes(1);
    expect(cotizacionesRepository.create).toHaveBeenCalledWith(
      expect.objectContaining({
        organizationId: 77,
        proyectoId: 300,
        subtotalNeto: 333000,
        total: 396270,
      })
    );
    expect(cotizacion.id).toBe(999);
  });
});
